var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"나는 한때 관리국 소속이었다.","JPN":"私は昔、管理局に所属していた。","ENG":"I used to be part of the Administration.","TWN":"我曾經是管理局的一員。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"내가 아는 그 관리국 말이야?","JPN":"私の知ってる、あの管理局？","ENG":"Is it the Administration that I know?","TWN":"你說的是我所知道的那個管理局嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"아마도 그렇겠지.","JPN":"おそらくな。","ENG":"Yes, probably.","TWN":"大概是吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"지금도 그때와 같은 관리국이라 부를 수 있을진 모르겠지만.","JPN":"今の管理局を、あの時と同じ管理局と呼べるかは分からないが。","ENG":"Though I'm not sure if it can still be called the same Administration as before.","TWN":"雖然不知道現在是否還能稱作是當時的管理局。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"우리가 처음 만났을 때, 그대에겐 찾는 사람이 있다고 했었지.","JPN":"初対面の時、そなたは人を探していると言っていたな。","ENG":"When we first met, you said you were looking for someone.","TWN":"我們第一次見面時，你說過你在找一個人。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그건… 버려진 형제들의 타깃인 날 말하는 거였나?","JPN":"そなたが探していたのは捨てられた兄弟のターゲット……某のことだったのか。","ENG":"Was that… me? The one the Brothers Abandoned was targeting?","TWN":"那個人…就是我嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"맞아.","JPN":"そうだ。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"하지만 내가 찾는 건 당신만이 아니었어.","JPN":"しかし私が探していたのはお前だけじゃない。","ENG":"But you weren't the only one I was after.","TWN":"但我並非只找你。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신과 연결점이 있는 다른 사람을 찾고 싶었거든.","JPN":"もう一人、お前と関わりのある人を探していたんだ。","ENG":"I was looking for someone connected to you.","TWN":"我想找一個與你有關的另一個人。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나와 연결점이 있다면… 그 사람도 관리국 출신인가?","JPN":"某と関わりのある者……その者も管理局出身なのか？","ENG":"Someone who's connected to me… Is that individual also from the Administration?","TWN":"和我有關…那個人也是管理局出身嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"對。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"아마도 내 아버지일 거다.","JPN":"多分、私の父親だろう。","ENG":"Most likely… my father.","TWN":"可能是我父親。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아마도 아버지일 거라니… 찾고 있는 사람이 누구인지도 모르는 거야?","JPN":"多分って……探している人が誰なのかも分からないの？","ENG":"\\"Most likely,\\" you say… You don't even know who you're looking for?","TWN":"什麼叫可能是你父親…你連要找的人是誰都不知道嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"나도 네 사부와 마찬가지로 과거에 대한 기억이 대부분 날아갔거든.","JPN":"私もお前の師匠と同じく、過去の記憶をほとんど失っているからな。","ENG":"Just like your master, I lost most of my memories.","TWN":"我也和你師父一樣，大部分過去的記憶都消失了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그렇게 된 직후엔 한동안 방황하기도 했었지.","JPN":"記憶を失った直後はしばらくの間彷徨いもした。","ENG":"I felt lost for a while right after it happened.","TWN":"在那之後，有一段時間我一直在四處遊蕩。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"관리국을 떠나면서 기억소거 시술을 받은 건가?","JPN":"管理局を去る時、記憶消去手術を受けたのか。","ENG":"Did they wipe your memory when you left the Administration?","TWN":"離開管理局時，接受了記憶消除手術嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"난 당신처럼 내 발로 관리국을 떠나지 않았어.","JPN":"私はお前のように自分の足で管理局を去ったわけじゃない。","ENG":"I didn't leave voluntarily like you did.","TWN":"我沒有像你一樣，主動離開管理局。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"최전선에서 큰 전투를 치른 뒤로… 기억의 대부분을 잃었거든.","JPN":"最前線で大規模の戦闘を経験し……記憶の大半を失った。","ENG":"After a major battle on the front lines… I lost most of my memories.","TWN":"在一次前線的大規模作戰後…我失去了大部分記憶。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"가까스로 살아 돌아왔지만, 관리국은 날 없는 사람 취급하더군.","JPN":"なんとか生還したものの、管理局で私は存在しない人間となっていた。","ENG":"I barely made it back alive, but the Administration acted like I didn't exist.","TWN":"好不容易活著回來，但管理局卻把我當成不存在的人。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그렇다면 그대는 어쩌다 관리국에 반목하는 자들과 함께하게 된 것이지?","JPN":"では、どういう経緯で管理局に敵対する集団と行動を共にすることになったのだ？","ENG":"So why did you end up working with a group opposing the Administration?","TWN":"那你為什麼會和一個反對管理局的團體在一起？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그쪽에서 먼저 연락책을 보냈어.","JPN":"あっちから連絡係を送って来たんだ。","ENG":"They approached me first.","TWN":"他們先派人聯繫了我。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"자길 도와주면 내 아버지의 행방을 찾도록 도와주겠다면서 말이야","JPN":"自分たちに協力したら、父の行方を探すのを手伝うと言ってな。","ENG":"Said if I helped them, they'd help me find my father.","TWN":"說只要我幫助他們，他們就會幫我尋找我父親的下落。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그럼, 그 조직이 사람을 해치는 나쁜 조직이란 걸 다 알면서도 도왔던 거야?","JPN":"じゃあ、その組織が人々を脅かす悪い組織だって分かった上で手伝ったの？","ENG":"So you helped them even though you knew they were bad guys?","TWN":"所以，你明明知道那個組織是會傷害人的，還是幫助了他們？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그럼에도 불구하고 따를 수밖에 없는 거다.","JPN":"分かっていても、従うしかないんだ。","ENG":"I had no choice.","TWN":"沒辦法，我只能聽命行事。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그게 버려진 형제들의 수장이 가진 힘이니까.","JPN":"それが捨てられた兄弟のリーダーの持つ力だからな。","ENG":"That's the kind of power their leader holds.","TWN":"這就是被遺棄的兄弟首領所擁有的權力。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그곳에서 일하는 조직원들은 대개 비슷한 사연을 가지고 있어.","JPN":"そこで働いている組織員は、皆似たような事情を抱えている。","ENG":"Most of the people there have similar stories.","TWN":"在那裡做事的組織成員大多都有相似的經歷。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"대정화전쟁을 기점으로 발생한 대규모 정보오염이 그들의 삶을 작은 파편조각으로 만들어 놓았거든.","JPN":"大浄化戦争を起点に発生した大規模な情報汚染が、彼らの人生をめちゃくちゃにした。","ENG":"The Grand Purification War left behind massive data corruption that shattered their lives into fragments.","TWN":"以大淨化戰爭為起點發生的大規模資訊汙染，將他們的生活變成碎片。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"정보오염…?","JPN":"情報汚染……？","ENG":"Data corruption…?","TWN":"資訊汙染？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"관리국이 가진 기술력이 침식 사태를 유발한다는 유명한 음모론 말이야?","JPN":"管理局の技術力が侵食事態をもたらすっていう、あの有名な陰謀論のこと？","ENG":"You mean that conspiracy theory? That the Administration's tech causes Corruption disasters?","TWN":"就是那個管理局所擁有的技術會引發侵蝕事態的著名陰謀論嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 음모론을 퍼뜨린 게 버려진 형제들이다. 그걸 숨기고 싶어하는 관리국과는 정반대지.","JPN":"その陰謀論を広めたのが捨てられた兄弟だ。管理局が隠したがるのとは正反対にな。","ENG":"That conspiracy theory was spread by the Brothers Abandoned. The exact opposite of the Administration that tried to hide it.","TWN":"散播那個陰謀論的就是被遺棄的兄弟。這和管理局想要隱藏的正好相反。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"정보오염은 침식 사태로 시작해서, 종국엔 오염된 정보를 소멸시킨다.","JPN":"情報汚染は侵食事態から始まり、最後には汚染された情報そのものを消滅させる。","ENG":"Data corruption starts with a Corruption disaster and ends with the destruction of the corrupted data.","TWN":"資訊汙染從侵蝕事態開始，最終會消滅被汙染的資訊。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"오염된 정보가 소멸한다는 건… 정확히 어떤 의미인 건데?","JPN":"汚染された情報が消滅するって……具体的にどういうことなの？","ENG":"Destruction of corrupted data…? What does that even mean?","TWN":"汙染的資訊會被消滅…這到底是什麼意思？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"망각, 소실, 왜곡. 그 모든 걸 아울러 존재했다는 개념 자체가 사라진다는 의미야.","JPN":"忘却、消失、歪曲。すべてひっくるめて、存在していたという概念そのものが消えるという意味だ。","ENG":"It means forgetfulness, erasure, and distortion. The very concept of something's existence just disappears.","TWN":"遺忘、喪失、扭曲。總而言之，就是存在過這個概念本身都會消失。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"대개는 자기 자신도 모르는 사이에 그 피해자가 되고 말지.","JPN":"ほとんどは自分も知らないうちに被害者になる。","ENG":"And most of the time, people don't even know it's happening to them.","TWN":"大多數人在不知不覺中就成了受害者。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"침식사태를 겪는 것도 모자라, 자기도 모르는 사이에 기억까지 잃다니…","JPN":"侵食事態を経験するだけでも辛いのに、自分も知らないうちに記憶まで失うなんて……","ENG":"So on top of the Corruption disaster, they lose their memories too without even realizing it…","TWN":"經歷侵蝕事態還不夠，還在不知不覺中失去記憶…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"엄청 무서운 일이었겠네.","JPN":"すごく怖い経験だったんだね。","ENG":"That's terrifying.","TWN":"這真是件可怕的事情呢。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"버려진 형제들의 수장은 자길 따르는 부하들의 구멍 난 기억을 관리국에 대한 증오로 메웠어.","JPN":"捨てられた兄弟のリーダーは、自分に従う部下たちが失っていた記憶の穴を、管理局への憎悪で埋めた。","ENG":"The leader of the Brothers Abandoned filled her followers' broken memories with hatred for the Administration.","TWN":"被遺棄的兄弟首領，利用對管理局的憎恨，來填補追隨者們記憶中的空洞。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"너희도 봤다시피, 사람을 꼭두각시처럼 조종하는 데엔 제법 효과적인 방법이지.","JPN":"お前たちも見た通り、人を操り人形にするにはなかなか効果的な方法でな。","ENG":"As you saw, it's a disturbingly effective way to control people like puppets.","TWN":"就像你看到的，這是可以將人當作傀儡操縱的有效方法。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그 사람들, 날 인질로 써서 사부를 해치려 했다고.","JPN":"あの人たち、私を人質にして師匠を殺そうとしたんだよ。","ENG":"They tried to hurt Master by using me as a hostage.","TWN":"那些人，把我當人質，想傷害師父。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그런 악당들이랑 잘도 참으면서 같이 일했구나?","JPN":"そんな悪いやつらと、よく一緒に仕事ができたね。","ENG":"So you actually managed to work with those villains and put up with them?","TWN":"你竟然能忍著和那樣的壞人一起做事？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"나라고 그들과 달랐을 거라는 생각은 하지 않는 게 좋아.","JPN":"私が彼らと違うと、思わないほうがいい。","ENG":"It's best not to think I'm any different from them.","TWN":"別以為我會和他們有什麼不同。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그들과 나에게 차이점이 있다면… 난 뒤늦게나마 더 나은 기로를 찾은 것뿐이니까.","JPN":"彼らと私の違いがあるとすれば……私は遅ればせながら、よりマシな選択肢を見つけたという点ぐらいだ。","ENG":"If there's a difference… it's that I eventually chose a better path.","TWN":"我和他們的區別在於…我只是後來找到更好的道路。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그래서, 그들의 뜻대로 움직인 덕에 원하는 걸 얻었나?","JPN":"それで、彼らの言いなりになった結果、望んでいたものは手に入ったのか？","ENG":"So, did cooperating with them get you what you wanted?","TWN":"所以，你幫他們做事後，有得到你想要的東西嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"아버지에 대한 작은 단서 하나.","JPN":"父に関する手がかりを1つ。","ENG":"Just one small clue about my father.","TWN":"關於父親的一點線索。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 사람이 속해 있던 전대의 유일한 생존자가… 기억을 지운 뒤 관리국을 떠났다는 것.","JPN":"あの人が所属していた戦隊の唯一の生き残りが……記憶を消した後管理局を去ったということだ。","ENG":"The only survivor of his division… left the Administration after erasing his memories.","TWN":"他在屬的戰隊中，是唯一的倖存者…記憶被消除後離開了管理局。"},"stage":{"bg":"CHAMBER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그리곤 1년 넘게 챔버를 전전하다, 다시 자신의 옛 고향인 KS-7에 거처를 차렸다는 걸 알게 됐지.","JPN":"そして1年以上チェンバーを転々とした後、再び自分の故郷であるKS-7に居を構えたと分かった。","ENG":"Then he wandered through Chamber for over a year, eventually settling down in his old hometown, KS-7.","TWN":"然後在強巴待了一年多，又回到他的故鄉KS-7定居。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이해가 안 되네.","JPN":"理解できないな。","ENG":"I don't get it.","TWN":"真搞不懂。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그럼 사부도, 어르신도, 그 버려진 형제들이란 조직도, 전부 같은 관리국 출신의 동료들인 거잖아!","JPN":"じゃあ師匠もおばあさんも、その捨てられた兄弟って組織も、全部管理局出身の仲間ってことじゃん！","ENG":"So Master, granny, and even those Brothers Abandoned people were all comrades from the same Administration!","TWN":"那麼師父、阿姨，還有被遺棄的兄弟這個組織，不全都是管理局出身的夥伴嗎！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"왜 적도 아니었던 사람들끼리 서로를 해치려고 그렇게 안달인 거야?","JPN":"敵でもなかった人同士、なんでお互いを傷つけようとするの？","ENG":"Then why are they so obsessed with hurting each other?","TWN":"明明彼此不是敵人，卻迫切地想要傷害彼此？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"형제들은 자신이 따르는 조직의 수장을 맹목적으로 따를 뿐이다.","JPN":"兄弟たちは、自分たちの組織のリーダーに盲目的に従っているだけだ。","ENG":"The Brothers Abandoned just follows their leader blindly.","TWN":"兄弟們只是盲目地追隨他們的組織首領。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그자의 선동과 기만은 어디까지가 진실이고 거짓인지 알 수 없으니까.","JPN":"あの者の扇動と欺瞞はどこまでが真実で、どこまでが嘘か分からない。","ENG":"It's impossible to tell how much of what she says is truth or manipulation.","TWN":"因為那個傢伙的煽動和欺騙，你無法分辨哪些是真實，哪些是謊言。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그래도 괜찮다면 말해주게.","JPN":"それでも、話せるなら話してくれぬか。","ENG":"If you don't mind, I have one more question.","TWN":"如果可以的話，告訴我吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"형제들이 날 제거하려 한 이유가 무엇이었는지.","JPN":"兄弟たちが某を排除しようとした理由は何なのか。","ENG":"Why exactly did they want me dead?","TWN":"兄弟們想要除掉我的理由是什麼？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"정확한 경위는 나도 모르지만…","JPN":"具体的な経緯は私にも分からないが……","ENG":"I don't know the full story, but…","TWN":"具體原因我也不清楚…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신이 머지 않은 미래에 세상을 멸망시킬 침식재난을 불러올 거라더군.","JPN":"お前が近い未来、世界を滅ぼす侵食災害を引き起こすと聞いた。","ENG":"They claim you will cause a Corruption disaster that would end the world in the foreseeable future.","TWN":"但他們說，你在不久的將來會引發一場滅世的侵蝕災難。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"세상을 멸망시키다니… 그게 무슨 소리야?","JPN":"世界を滅ぼすって……どういうこと？","ENG":"End the world… Seriously?","TWN":"滅世？這是什麼意思？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어르신도 알잖아. 침식사태는 사람이 일으키는 게 아니라 불가항력적 재난이라고! 그런 말도 안 되는 거짓말을 믿어?","JPN":"おばあさんも知ってるでしょ。侵食事態は人間が引き起こすものじゃなくて、不可抗力な災害だって！　そんなバカな嘘を信じるの？","ENG":"You know better than that, granny. Corruption disasters aren't caused by people! That's total nonsense!","TWN":"你也知道吧。侵蝕事態是不可抗力的災難，不是人為引發的！你相信那種荒唐的謊言嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그렇다면 지수 양의 생각도 묻고 싶군.","JPN":"なら、シノ君の意見が聞きたい。","ENG":"Then what do you think, Jisoo?","TWN":"那麼，我想知道你的想法。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"정말로 내가 그런 짓을 할 사람이라고 생각하나?","JPN":"本当に某がそのようなことをする人間だと思うか？","ENG":"Do you really believe I'm capable of something like that?","TWN":"你真的認為我會是那樣的人嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"아직 속단할 순 없겠지.","JPN":"まだ判断できないな。","ENG":"It's too soon to say.","TWN":"還不能妄下定論。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"난 그자의 말을 맹신하지도 않고, 당신의 과거도 정확히 모르니까.","JPN":"私はあの者の言葉を無暗に信用したりはしないが、お前の過去についても詳しいことは知らないからな。","ENG":"I don't trust the leader's words blindly, and I don't fully know your past either.","TWN":"我不盲目相信那個傢伙的話，也不清楚你的過去。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"허나 그런 불확실함을 갖고도, 그대는 날 도왔어. 그대의 조직을 명백히 배반하면서까지 말이지.","JPN":"だがそなたは某を助けた。所属している組織を裏切るようなことをしてまで。","ENG":"And yet, you helped me. Even if it meant clearly betraying your own organization.","TWN":"但你幫了我，甚至背叛你的組織。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"앞서 말했듯이, 난 과거에 잃어버린 걸 찾고 있어.","JPN":"さっきも言ったように、私は過去に失ったものを探している。","ENG":"Like I said, I'm trying to recover what I've lost in the past.","TWN":"就像我之前說的，我在找尋過去失去的東西。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그러니 과거에 묶여 살아가는 자들보단, 과거를 되찾고 싶어하는 쪽에 협조하기로 한 것뿐이야.","JPN":"だから過去に囚われて生きている奴らよりは、過去を取り戻したがっている人間の側につくことにしただけだ。","ENG":"That's why I chose to side with someone chasing their past instead of being shackled to it.","TWN":"所以，我只是選擇與那些想找回過去的人合作，而不是與被過去束縛的人。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…잘 알겠네.","JPN":"……分かった。","ENG":"…I understand.","TWN":"…我明白了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대의 과거를 찾는 데 내가 얼마나 보탬이 될진 모르겠지만, 나도 최선을 다 해보지.","JPN":"そなたの過去を探すことに、某がどれほど役に立つかは分からんが、最善を尽くしてみよう。","ENG":"I don't know how much help I'll be, but I'll do what I can to support you.","TWN":"雖然不知道我能幫你找回多少過去，但我會盡力而為。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그런 식으로 매듭지어도 괜찮은 거야?","JPN":"そんな結論でいいの？","ENG":"That's it? You're letting it go just like that?","TWN":"就這樣嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"저 말대로면 어르신은 처음부터 지금까지 쭉 사부를 속여왔다는 거잖아.","JPN":"今聞いた話が本当なら、おばあさんは最初から師匠を騙してたってことでしょう？","ENG":"If she's telling the truth, granny's been lying to you this whole time!","TWN":"照她這麼說，她從頭到尾都在騙師父。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"속았다 한들 별 수 있겠나? 우리 둘이 힘을 합쳐도 그녀 하나를 당해낼 재간이 없는데.","JPN":"騙されたところで仕方あるまい。我ら2人が力を合わせても、彼女1人に勝てないのだから。","ENG":"What choice do I have? Even together, we wouldn't stand a chance against her.","TWN":"就算被騙又能怎樣？我們倆聯手也打不過她一個。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"앗… 그것도 틀린 말은 아니네.","JPN":"あっ……確かにそうだね。","ENG":"Ah… Okay, fair point.","TWN":"呃…這話也沒錯。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"내가 당신의 적으로 돌아설 일은 없을 거야.","JPN":"私がお前の敵側に回ることはない。","ENG":"I'll never turn against you.","TWN":"我不會成為你的敵人。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"만에 하나 그런 일이 생긴다면… 적어도 조용히 떠나겠다고 약속하지.","JPN":"万が一そんなことになったら……せめて静かに立ち去ると約束しよう。","ENG":"And if I ever do… I promise I'll leave quietly.","TWN":"萬一發生那樣的事…我答應你，至少我會安靜地離開。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그럼, 우린 한 배를 탔으니 급여는 없는 셈 쳐도 되겠나?","JPN":"では、同じ船に乗った仲間ということで、賃金はなしでもよいか？","ENG":"In that case, since we're in this together, I assume I don't have to pay you?","TWN":"既然我們現在同一條船上，那是不是可以不要發薪水給你？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"진검승부로 날 이길 자신이 있다면 얼마든지.","JPN":"真剣勝負で私に勝てる自信があるならそうしてもいい。","ENG":"Sure, if you think you can beat me in a real duel.","TWN":"如果你有自信能在劍術較量中打敗我，當然沒問題。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"실없는 농담일세.","JPN":"冗談だ。","ENG":"It's a joke, clearly.","TWN":"開個玩笑。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"두 사람은 한숨 돌리고 있게. 오늘 식사는 내가 담당이니까.","JPN":"2人は少し休みたまえ。今日の食事当番は某ゆえ。","ENG":"You two take a break. I'll handle today's meal.","TWN":"你們倆休息一下吧，今天的晚餐由我來負責。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"기억에도 없는 사람을 찾고 있다는 말… 솔직히 난 아직도 못 믿겠어.","JPN":"記憶にもない人を探してるって話……正直私はまだ信じられないよ。","ENG":"Searching for someone you don't even remember… Honestly, I still can't believe it.","TWN":"老實說，我還是無法相信你在找一個沒有記憶的人。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"상관없다.","JPN":"構わない。","ENG":"Doesn't matter.","TWN":"無所謂。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"믿건 말건, 도움이 되면 서로 이용하는 거야.","JPN":"信じようが信じないが、役立つなら互いに利用するだけだ。","ENG":"Believe it or not, if it's useful, we use each other.","TWN":"信不信都一樣，只要能互相幫助，就是互相利用。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그래도 서로 이해할 수 있으면 좋잖아!","JPN":"でも、お互いのこと分かり合えたらもっといいじゃん！","ENG":"Still, wouldn't it be nice to understand each other?!","TWN":"但如果能互相理解，不是更好嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"기껏 등을 맡기기로 했는데, 정작 위기일 때 뒤를 믿지 못하면 무슨 의미가 있어?","JPN":"背中を任せようってなったのに、いざという時に信じられなかったら意味がないよ！","ENG":"We agreed to watch each other's backs. But if you can't trust someone when it matters, what's the point?","TWN":"好不容易決定把性命交給對方，如果在危機時不信任對方，那有什麼意義？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"진정성 있는 이야길 몇 번 주고받으면 흔쾌히 목숨을 맡기는 사이가 되기라도 하나?","JPN":"本音を打ち明けて何回か話し合えば、簡単に命を預けられる仲になれるとでもいうのか？","ENG":"You think trading a few honest words makes us close enough to risk our lives for each other?","TWN":"難道多聊幾次真心話，就能變成可以交付性命的關係嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그건… 나도 몰라.","JPN":"そんなの……私だって分かんない。","ENG":"That… I don't know.","TWN":"這個…我也不知道。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그치만 뭐라도 얘기하는 게 아무 말없이 눈치만 살피는 것보단 낫지 않아?","JPN":"でも、何でも話すほうが、何も言わずに顔色を伺うよりはマシじゃない？","ENG":"But it's better than saying nothing and just tiptoeing around, right?","TWN":"但是，說些什麼總比什麼都不說，只會察言觀色要好吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"믿든 말든 네 마음이지만… 내 눈엔 보여선 안 될 게 보여.","JPN":"信じるか信じないかはお前の勝手だが……私には見えてはならないものが見える。","ENG":"Believe it or not, it's your choice… But I'm seeing things I shouldn't be seeing right now.","TWN":"信不信由你…但在我眼中，能看到一些不該看到的東西。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그게… 뭔데? 유령 같은 거야?","JPN":"え……何？　幽霊みたいなもの？","ENG":"Like… what? A ghost?","TWN":"那…是什麼？像幽靈一樣嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"비슷한 면도 있지. 아주 강렬한 감정이 남긴 <color=#ffd34c>사념의 불꽃</color>을 보는 거니까.","JPN":"似ているところもある。非常に強烈な感情が残した<color=#ffd34c>思念の炎</color>だから。","ENG":"Something like that. It's a <color=#ffd34c>Flame of Sentiment</color> left behind by intense emotions.","TWN":"和幽靈有點像。因為我能看到非常強烈的感情留下的<color=#ffd34c>意念之火</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"원한이나 미련 같은 거 말이야?","JPN":"恨みとか未練みたいな？","ENG":"Like a grudge or regret?","TWN":"像怨恨或留戀之類的？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그래. 그런 원한이나 미련은 혼자서 품지 않아. 사람에서 사람으로 이어지는 감정이거든.","JPN":"そうだ。そういった負の感情は、一人の中にあるものじゃない。人から人へと繋がる感情だ。","ENG":"Exactly. And those feelings never exist in isolation. They always connect from one person to another.","TWN":"對。那種怨恨或留戀並非獨自存在，是一種人與人之間相連的感情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그런데, 지금 내 곁엔 그 무엇과도 이어지지 않은 미련이 떠돌며 방황하고 있어.","JPN":"だが、何故か誰とも繋がっていない未練が一つ、今私の側で彷徨っている。","ENG":"But right now, there's one wandering near me, completely unbound from anything or anyone.","TWN":"但是，現在我身邊徘徊的留戀，卻和任何人都不相連。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그 무엇과도 이어지지 않은… 미련.","JPN":"誰とも繋がってない……未練。","ENG":"A regret… that's not bound to anything.","TWN":"和任何人都不相連的…留戀。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그럼 어르신은 그 미련의 주인을 찾고 있던 거구나.","JPN":"じゃあおばあさんは、その未練の主を探しているんだね。","ENG":"So you're looking for whoever that regret belongs to.","TWN":"所以你是在找尋那個留戀的主人吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"보통은 헛소리로 치부하고 말 텐데, 제법 진지하게 믿는군.","JPN":"普通なら戯言だと無視されるような話だが、随分と真摯に信じるんだな。","ENG":"Most people would write it off as nonsense. But you're surprisingly serious.","TWN":"通常其他人聽到會覺得我在胡言亂語，但你竟然還真的相信。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"카운터- 침식체- 시간여행- 보고도 안 믿기는 일이야 세상 천지에 널렸는데 뭐.","JPN":"カウンター、侵食体、タイムトラベル……直接目にしても信じられないようなことが、この世界にはいっぱいあるからね。","ENG":"I mean, there's already enough weird stuff out in the world, like Counters, C.O.s, and time travel.","TWN":"制裁者、侵蝕體、時間旅行，這世界上讓人難以相信的事情多的是。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…네 말대로야.","JPN":"……その通りだ。","ENG":"…Fair enough.","TWN":"…你說得對。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"난 이 미련이 누구에게서 왔는지 찾고 있어.","JPN":"私はこの未練が誰から来たものなのかを調べている。","ENG":"I want to know whose regret this is.","TWN":"我在找尋這個留戀來自何處。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"기억 나지 않는 과거에 매달려서라도… 내가 과거에 어떤 존재였는지 알고 싶다.","JPN":"思い出せない過去の記憶にすがってでも……自分がどんな存在だったのか知りたい。","ENG":"Even if it means chasing after a forgotten past… I want to know who I used to be.","TWN":"就算必須依靠想不起的過去…我也想知道過去的我是個怎樣的人。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"넌 그런 걸 이해하진 못하겠지만.","JPN":"お前には理解できないだろうがな。","ENG":"Though I doubt you'd understand that.","TWN":"雖然你可能無法理解。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"응, 이해 못해. 난 과거를 잃어본 경험도, 그걸 애써 찾으려 해본 적도 없으니까.","JPN":"うん、理解できない。私には過去を失った経験も、それを取り戻そうとした経験もないもん。","ENG":"Yeah, I don't. I've never lost my past or tried to find it.","TWN":"嗯，無法理解。我既沒有失去過過去，也沒有努力找回過。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"하지만 어르신이 찾고 싶어하는 과거 못지 않게 소중한 사람은 있어.","JPN":"でもおばあさんが探そうとしている過去と同じぐらい、大切な人ならいる。","ENG":"But I do have someone just as precious to me like you wanting to find your past, granny.","TWN":"但是，我有一個不亞於你想要找回的過去，是一個很重要的人。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그 사람을 방해하지만 않는다면 나도 어르신을 도와 줄게.","JPN":"その人の邪魔さえしないなら、私もおばあさんを手伝ってあげるよ。","ENG":"As long as you don't get in the way, I'll help you too.","TWN":"只要你不妨礙那個人，我也會幫你的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"마무리가 엉성해서 미안하군. 다른 사람에게 이런 이야길 한 건 처음이라.","JPN":"まとめ方が雑で悪いな。他人にこんな話をしたのは初めてで。","ENG":"Sorry if that came out messy. I've never told this story to anyone before.","TWN":"收尾收得這麼爛，很抱歉。這是我第一次和別人說這些。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"됐어. 당연히 엉성할 수밖에 없잖아.","JPN":"いいよ。仕方ないもん。","ENG":"It's fine. Of course it's messy.","TWN":"沒關係，爛是很正常的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그 이야기의 결말은 어르신이 찾고 싶은 기억을 되찾았을 때 맺어지는 거니까.","JPN":"その話は、おばあさんが探してる記憶を取り戻した時に完結するんだから。","ENG":"Because that story only reaches its end when you recover the memories you've been searching for.","TWN":"因為這個故事的結局，只有在你找回記憶時才能劃下句點。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"어쨌든, 앞으로도 잘 부탁하지.","JPN":"とにかく、これからもよろしく頼む。","ENG":"Anyway, I look forward to working with you.","TWN":"總之，今後也請多關照。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…앤디.","JPN":"……アンディー。","ENG":"…Andy.","TWN":"…安狄。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"오?","JPN":"お？","ENG":"Oh?","TWN":"喔？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이제 꼬맹이라고 안 부르기로 한 거야? 살짝 섭섭할지도?","JPN":"もうガキって呼ぶのやめたの？　ちょっと寂しいかも？","ENG":"You're not calling me kid anymore? Kinda feels weird.","TWN":"不叫我小鬼啦？有點不習慣呢？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"말 만한 덩치를 하고서 애취급을 받고 싶어하는 것도 참 몰염치하군.","JPN":"その体つきでガキ扱いされたいとは、恥知らずにもほどがあるな。","ENG":"That's pretty shameless, wanting to be treated like a child when you're clearly not one.","TWN":"明明已經長得人高馬大，還想被當成小孩對待，真是厚臉皮。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"흥, 하여간 마무리는 영 꽝이라니까.","JPN":"ふん、いっつも最後はこんなしょーもないまとめ方よね。","ENG":"Ugh, you always have to ruin the moment!","TWN":"哼，你真的很不會說話。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부우- 나도 밥 하는 거 도울래!","JPN":"師匠～私もご飯の準備手伝うよ！","ENG":"Masteeeer! I'll help with cooking too!","TWN":"師父～我也去幫你做飯！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L38_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_SILHOUETTE","text":{"KOREA":"네 곁을 맴도는 그건 누군가의 사념이야.","JPN":"君の側に漂うそれは、誰かの思念だ。","ENG":"That thing lingering near you… it's someone's sentiment.","TWN":"盤旋在你身邊的，是某人的意念。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_SILHOUETTE","text":{"KOREA":"너와 이어져 있던 결속이 끊어진 흔적이지.","JPN":"君と繋がっていた結束が途切れた痕跡と言えるな。","ENG":"A trace left behind when your bond with them was severed.","TWN":"是與你相連的羈絆被切斷的痕跡。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신도 나랑 같은 게 보이는 건가?","JPN":"お前にも私と同じものが見えているのか？","ENG":"Can you see it too?","TWN":"你也能和我看到一樣的東西嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_SILHOUETTE","text":{"KOREA":"그런 눈을 가진 사람을 알고 있거든.","JPN":"そんな目をした人を知っている。","ENG":"I know someone who shares that kind of sight.","TWN":"我認識一個有著那種眼睛的人。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_SILHOUETTE","text":{"KOREA":"네가 원한다면, 그 사람을 찾는 걸 내가 도와 줄게.","JPN":"望むなら、その人を探すことに協力しよう。","ENG":"If you want, I can help you find that person.","TWN":"如果你願意，我可以幫你找那個人。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_SILHOUETTE","text":{"KOREA":"어때?","JPN":"どうだ？","ENG":"What do you say?","TWN":"怎麼樣？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_SILHOUETTE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"설령 그자의 말이 거짓이라 해도…","JPN":"たとえあの者の話が嘘だとしても……","ENG":"Even if she was lying…","TWN":"就算她的話是假的…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"여기까지 온 이상, 물러서진 않겠어.","JPN":"ここまで来た以上、引き下がりはしない。","ENG":"I've come too far to turn back now.","TWN":"既然已經走到這一步，我就不會退縮。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};